    <text x="195" y="218" fill="#e4e4e7" font-size="14" font-weight="700" text-anchor="middle" font-family="sans-serif">Coin C · Hypothetical alt</text>
    <text x="195" y="262" fill="#8b8b93" font-size="13" text-anchor="middle" font-family="sans-serif">$2 per coin</text>
    <text x="505" y="318" fill="#e4e4e7" font-size="14" font-weight="700" text-anchor="middle" font-family="sans-serif">Coin C · Hypothetical alt</text>
